<script>
  // ─────────────────────────────────────────────
  //  Fractal Tree — core drawing logic
  // ─────────────────────────────────────────────
  const canvas  = document.getElementById('treeCanvas');
  const ctx     = canvas.getContext('2d');
  const slider  = document.getElementById('depthSlider');
  const depthLbl = document.getElementById('depthLabel');
  const statBranches = document.getElementById('statBranches');
  const statCalls    = document.getElementById('statCalls');
  const statTime     = document.getElementById('statTime');

  let totalCalls = 0;
  let totalBranches = 0;

  // Hue shifts as depth increases for a rainbow-gradient effect
  function branchColor(depth, maxDepth) {
    const t = 1 - depth / maxDepth;          // 0 (trunk) → 1 (tips)
    const hue = Math.round(200 - t * 160);   // blue → green → yellow
    const lightness = 35 + t * 45;
    return `hsl(${hue}, 80%, ${lightness}%)`;
  }

  /**
   * Recursive branch drawing.
   * @param {number} x       start x
   * @param {number} y       start y
   * @param {number} angle   angle in radians (0 = up)
   * @param {number} length  branch length in px
   * @param {number} depth   remaining recursion levels
   * @param {number} maxDepth original max depth (for colouring)
   */
  function drawBranch(x, y, angle, length, depth, maxDepth) {
    totalCalls++;
    if (depth === 0) return;

    const x2 = x + Math.sin(angle) * length;
    const y2 = y - Math.cos(angle) * length;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = branchColor(depth, maxDepth);
    ctx.lineWidth   = Math.max(0.5, depth * 0.8);
    ctx.lineCap     = 'round';
    ctx.stroke();

    totalBranches++;

    const spread  = 0.42;          // angle spread (radians)
    const shrink  = 0.72;          // length multiplier per level
    const wobble  = 0.06;          // slight asymmetry for natural look

    drawBranch(x2, y2, angle - spread + wobble, length * shrink, depth - 1, maxDepth);
    drawBranch(x2, y2, angle + spread - wobble, length * shrink, depth - 1, maxDepth);
  }

  function drawTree(depth) {
    totalCalls   = 0;
    totalBranches = 0;

    const w = canvas.width;
    const h = canvas.height;
    ctx.clearRect(0, 0, w, h);

    const trunkX      = w / 2;
    const trunkY      = h - 20;
    const trunkLength = h * 0.22;

    const t0 = performance.now();
    drawBranch(trunkX, trunkY, 0, trunkLength, depth, depth);
    const t1 = performance.now();

    statBranches.textContent = totalBranches.toLocaleString();
    statCalls.textContent    = totalCalls.toLocaleString();
    statTime.textContent     = (t1 - t0).toFixed(2) + ' ms';
  }

  // ─────────────────────────────────────────────
  //  Stack visual (decorative, not real frames)
  // ─────────────────────────────────────────────
  function updateStackVisual(depth) {
    const container = document.getElementById('stackVisual');
    container.innerHTML = '';
    const show = Math.min(depth, 6);
    for (let i = 0; i <= show; i++) {
      const frame = document.createElement('div');
      frame.className = 'stack-frame' + (i === show && depth > 6 ? ' overflow' : '');
      const w = 80 + i * 28;
      frame.style.width = w + 'px';
      frame.textContent = i === 0
        ? 'drawBranch(0) ← base case'
        : `drawBranch(${i})`;
      container.appendChild(frame);
    }
    if (depth > 6) {
      const more = document.createElement('div');
      more.className = 'stack-frame overflow';
      more.style.width = '260px';
      more.textContent = `… ${depth - 6} more frames hidden (depth ${depth})`;
      container.appendChild(more);
    }
  }

  // ─────────────────────────────────────────────
  //  Performance table
  // ─────────────────────────────────────────────
  function buildPerfRows(currentDepth) {
    const container = document.getElementById('perfRows');
    container.innerHTML = '';
    const maxCalls = Math.pow(2, 12) - 1;

    for (let d = 1; d <= 12; d++) {
      const calls  = Math.pow(2, d) - 1;
      const pct    = (calls / maxCalls) * 100;
      const active = d === currentDepth;

      const hue = d <= 4 ? 142 : d <= 8 ? 40 : 0;   // green / amber / red

      const row = document.createElement('div');
      row.style.cssText = `
        display:flex; align-items:center; gap:10px;
        opacity:${active ? '1' : '0.55'};
        transition: opacity 0.3s;
      `;
      row.innerHTML = `
        <span style="font-size:0.75rem;color:#8b949e;width:52px;text-align:right;flex-shrink:0">
          depth ${d}
        </span>
        <div style="flex:1;background:#0d1117;border:1px solid #30363d;border-radius:6px;overflow:hidden;height:8px">
          <div style="width:${pct.toFixed(1)}%;height:100%;background:hsl(${hue},70%,45%);border-radius:6px;transition:width 0.4s"></div>
        </div>
        <span style="font-size:0.75rem;color:#58a6ff;width:72px;flex-shrink:0">
          ${calls.toLocaleString()} calls
        </span>
      `;
      container.appendChild(row);
    }
  }

  // ─────────────────────────────────────────────
  //  Slider event
  // ─────────────────────────────────────────────
  function onDepthChange() {
    const depth = parseInt(slider.value, 10);
    depthLbl.textContent = depth;
    drawTree(depth);
    updateStackVisual(depth);
    buildPerfRows(depth);
  }

  slider.addEventListener('input', onDepthChange);

  // Initial draw
  onDepthChange();
</script>
</body>
</html>
