                </div>
            </div>
        </div>

        <div class="stats-bar">
            <div class="stat">
                <div class="stat-value" id="statBranches">—</div>
                <div class="stat-label">Total Branches</div>
            </div>
            <div class="stat">
                <div class="stat-value" id="statCalls">—</div>
                <div class="stat-label">Recursive Calls</div>
            </div>
            <div class="stat">
                <div class="stat-value" id="statStack">—</div>
                <div class="stat-label">Max Stack Depth</div>
            </div>
            <div class="stat">
                <div class="stat-value" id="statTime">—</div>
