<script>
    const canvas  = document.getElementById('treeCanvas');
    const ctx     = canvas.getContext('2d');
    const slider  = document.getElementById('depthSlider');
    const display = document.getElementById('depthDisplay');

    // Stats elements
    const statBranches = document.getElementById('statBranches');
    const statCalls    = document.getElementById('statCalls');
    const statStack    = document.getElementById('statStack');
    const statTime     = document.getElementById('statTime');

    let callCount   = 0;
    let maxDepthSeen = 0;

    // ─── Colour palette: trunk = warm brown, tips = cool cyan/blue ───────────
    function branchColor(currentDepth, maxDepth) {
        const t = currentDepth / maxDepth;          // 0 = trunk, 1 = tips
        // Interpolate hue: 30 (warm orange-brown) → 180 (cyan)
        const hue = 30 + t * 150;
        const sat = 60 + t * 30;
        const lit = 35 + t * 35;
        return `hsl(${hue}, ${sat}%, ${lit}%)`;
    }

    // ─── Recursive draw function ──────────────────────────────────────────────
    function drawBranch(x1, y1, angle, length, depth, maxDepth) {
        if (depth === 0) return;          // ← BASE CASE: prevents infinite recursion

        callCount++;
        maxDepthSeen = Math.max(maxDepthSeen, maxDepth - depth + 1);

        const x2 = x1 + Math.cos(angle) * length;
        const y2 = y1 + Math.sin(angle) * length;

        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);

        // Line width tapers from trunk to tips
        ctx.lineWidth = Math.max(0.5, (depth / maxDepth) * 10);
        ctx.strokeStyle = branchColor(maxDepth - depth, maxDepth);

        // Glow on deeper branches (tips)
        if (depth <= 3) {
            ctx.shadowColor = `hsl(${180 + (3 - depth) * 20}, 80%, 60%)`;
            ctx.shadowBlur  = 6;
        } else {
            ctx.shadowBlur = 0;
        }

        ctx.stroke();

        const newLength = length * 0.72;
        const spread    = Math.PI / 5.5;   // ~32.7°

        // Left child branch
        drawBranch(x2, y2, angle - spread, newLength, depth - 1, maxDepth);
        // Right child branch
        drawBranch(x2, y2, angle + spread, newLength, depth + 1 > maxDepth
            ? depth - 1 : depth - 1, maxDepth);
    }

    // ─── Main render ──────────────────────────────────────────────────────────
    function drawTree(depth) {
        callCount    = 0;
        maxDepthSeen = 0;

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Subtle radial glow at base
        const grd = ctx.createRadialGradient(
            canvas.width / 2, canvas.height, 10,
            canvas.width / 2, canvas.height, 220
        );
        grd.addColorStop(0,   'rgba(0, 212, 255, 0.04)');
        grd.addColorStop(1,   'rgba(0,0,0,0)');
        ctx.fillStyle = grd;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        const startX   = canvas.width / 2;
        const startY   = canvas.height - 20;
        const trunkLen = canvas.height * 0.22;

        const t0 = performance.now();
        drawBranch(startX, startY, -Math.PI / 2, trunkLen, depth, depth);
        const t1 = performance.now();

        // Update stats
        const totalBranches = Math.pow(2, depth + 1) - 1;
        statBranches.textContent = totalBranches.toLocaleString();
        statCalls.textContent    = callCount.toLocaleString();
        statStack.textContent    = depth;
        statTime.textContent     = (t1 - t0).toFixed(2);
    }

    // ─── Slider interaction ───────────────────────────────────────────────────
    slider.addEventListener('input', () => {
        const d = parseInt(slider.value, 10);
        display.textContent = d;
        display.style.color = d >= 10 ? '#ff4d6d' : '#00d4ff';
        display.style.textShadow = d >= 10
            ? '0 0 20px rgba(255,77,109,0.7)'
            : '0 0 20px rgba(0,212,255,0.6)';
        drawTree(d);
    });

    // ─── Responsive canvas sizing ─────────────────────────────────────────────
    function resizeCanvas() {
        const maxW = Math.min(760, window.innerWidth - 60);
        canvas.style.width  = maxW + 'px';
        canvas.style.height = Math.round(maxW * (480 / 760)) + 'px';
    }

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    // ─── Initial draw ─────────────────────────────────────────────────────────
    drawTree(parseInt(slider.value, 10));
</script>
</body>
</html>
