  <script>
    'use strict';

    /* ── Canvas setup ── */
    const canvas  = document.getElementById('treeCanvas');
    const ctx     = canvas.getContext('2d');

    /* ── Controls ── */
    const depthSlider = document.getElementById('depthSlider');
    const angleSlider = document.getElementById('angleSlider');
    const ratioSlider = document.getElementById('ratioSlider');
    const depthBadge  = document.getElementById('depthBadge');
    const angleBadge  = document.getElementById('angleBadge');
    const ratioBadge  = document.getElementById('ratioBadge');
    const statsEl     = document.getElementById('stats');
    const warningEl   = document.getElementById('depth-warning');
    const branchCountEl = document.getElementById('branchCount');

    /* ── State ── */
    let totalBranches = 0;

    /* ── Colour palette: trunk → tip ── */
    function branchColor(depth, maxDepth) {
      const t = 1 - depth / maxDepth;   // 0 = trunk, 1 = tip
      // Interpolate: warm brown → green → bright yellow-green
      const r = Math.round(139 - t * 80);
      const g = Math.round(90  + t * 120);
      const b = Math.round(43  - t * 30);
      return `rgb(${r},${g},${b})`;
    }

    /* ── Recursive draw ── */
    function branch(x1, y1, angle, length, depth, maxDepth) {
      if (depth === 0) return;

      totalBranches++;

      const x2 = x1 + length * Math.cos(angle);
      const y2 = y1 - length * Math.sin(angle);

      const spread = (parseInt(angleSlider.value, 10) * Math.PI) / 180;
      const ratio  = parseInt(ratioSlider.value, 10) / 100;

      // Trunk is thicker; tips are thin
      const lineWidth = Math.max(0.5, (depth / maxDepth) * 6);

      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = branchColor(depth, maxDepth);
      ctx.lineWidth   = lineWidth;
      ctx.lineCap     = 'round';
      ctx.stroke();

      const childLen = length * ratio;
      branch(x2, y2, angle - spread, childLen, depth - 1, maxDepth);
      branch(x2, y2, angle + spread, childLen, depth - 1, maxDepth);
    }

    /* ── Main draw ── */
    function draw() {
      const depth  = parseInt(depthSlider.value, 10);
      const W      = canvas.width;
      const H      = canvas.height;
      const trunkLen = H * 0.22;

      ctx.clearRect(0, 0, W, H);

      totalBranches = 0;
      branch(W / 2, H - 10, Math.PI / 2, trunkLen, depth, depth);

      // Stats
      const totalPossible = Math.pow(2, depth + 1) - 1;
      statsEl.textContent = `Branches drawn: `;
      statsEl.innerHTML =
        `Branches drawn: <span>${totalBranches.toLocaleString()}</span>` +
        ` &nbsp;|&nbsp; Max stack depth during draw: <span>${depth}</span>` +
        ` &nbsp;|&nbsp; 2<sup>${depth+1}</sup>−1 = <span>${totalPossible.toLocaleString()}</span>`;

      // Warning banner
      if (depth >= 11) {
        branchCountEl.textContent = totalPossible.toLocaleString();
        warningEl.classList.add('visible');
      } else {
        warningEl.classList.remove('visible');
      }
    }

    /* ── Slider listeners ── */
    depthSlider.addEventListener('input', () => {
      depthBadge.textContent = depthSlider.value;
      draw();
    });

    angleSlider.addEventListener('input', () => {
      angleBadge.textContent = angleSlider.value + '°';
      draw();
    });

    ratioSlider.addEventListener('input', () => {
      ratioBadge.textContent = (parseInt(ratioSlider.value, 10) / 100).toFixed(2);
      draw();
    });

    /* ── Responsive canvas ── */
    function resizeCanvas() {
      const maxW = Math.min(640, window.innerWidth - 64);
      canvas.width  = maxW;
      canvas.height = Math.round(maxW * 0.656);
      draw();
    }

    window.addEventListener('resize', resizeCanvas);

    /* ── Init ── */
    resizeCanvas();
  </script>

</body>
</html>
