     JAVASCRIPT
═══════════════════════════════════════════════ -->
<script>
  /* ── Canvas setup ── */
  const canvas  = document.getElementById('treeCanvas');
  const ctx     = canvas.getContext('2d');

  /* ── Slider references ── */
  const depthSlider = document.getElementById('depthSlider');
  const angleSlider = document.getElementById('angleSlider');
  const ratioSlider = document.getElementById('ratioSlider');
  const depthVal    = document.getElementById('depthVal');
  const angleVal    = document.getElementById('angleVal');
  const ratioVal    = document.getElementById('ratioVal');

  /* ── Stat elements ── */
  const statBranches = document.getElementById('statBranches');
  const statDepth    = document.getElementById('statDepth');
  const statTime     = document.getElementById('statTime');

  /* ── Warning banner ── */
  const warningBanner   = document.getElementById('warningBanner');
  const warnBranchCount = document.getElementById('warnBranchCount');

  /* ── Stack visualiser ── */
  const stackVis = document.getElementById('stackVis');

  /* ─────────────────────────────────────────────
     FRACTAL TREE DRAWING (recursive)
  ───────────────────────────────────────────── */
  let branchCount = 0;
  let maxReachedDepth = 0;

  /**
   * Recursively draws one branch of the fractal tree.
   * @param {number} x        - start x
   * @param {number} y        - start y
   * @param {number} length   - branch length in px
   * @param {number} angle    - angle in radians (0 = up)
   * @param {number} depth    - remaining depth
   * @param {number} maxDepth - original max depth (for colour mapping)
   * @param {number} spread   - half-angle spread in radians
   * @param {number} ratio    - child/parent length ratio
   */
  function drawBranch(x, y, length, angle, depth, maxDepth, spread, ratio) {
    if (depth === 0) return;   // ← base case

    branchCount++;
    const currentDepth = maxDepth - depth + 1;
    if (currentDepth > maxReachedDepth) maxReachedDepth = currentDepth;

    // Endpoint
    const x2 = x + Math.sin(angle) * length;
    const y2 = y - Math.cos(angle) * length;

    // Colour: trunk = warm brown, tips = bright green
    const t = (maxDepth - depth) / (maxDepth - 1 || 1);
    const r = Math.round(139 + (63  - 139) * t);   // 139 → 63
    const g = Math.round(90  + (200 - 90)  * t);   // 90  → 200
    const b = Math.round(43  + (80  - 43)  * t);   // 43  → 80

    // Line width: thick at trunk, thin at tips
    const lw = Math.max(0.5, (depth / maxDepth) * 6);

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = `rgb(${r},${g},${b})`;
    ctx.lineWidth   = lw;
    ctx.lineCap     = 'round';
    ctx.stroke();

    // Leaf glow at tips
    if (depth === 1) {
      ctx.beginPath();
      ctx.arc(x2, y2, lw * 1.5, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${r},${g},${b},0.6)`;
      ctx.fill();
    }

    // Recurse
    drawBranch(x2, y2, length * ratio, angle - spread, depth - 1, maxDepth, spread, ratio);
    drawBranch(x2, y2, length * ratio, angle + spread, depth - 1, maxDepth, spread, ratio);
  }

  /* ─────────────────────────────────────────────
     MAIN DRAW FUNCTION
  ───────────────────────────────────────────── */
  function draw() {
    const depth  = parseInt(depthSlider.value, 10);
    const spread = (parseInt(angleSlider.value, 10) * Math.PI) / 180;
    const ratio  = parseInt(ratioSlider.value, 10) / 100;

    // Reset counters
    branchCount      = 0;
    maxReachedDepth  = 0;

    // Clear canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Subtle grid background
    ctx.strokeStyle = '#1a2030';
    ctx.lineWidth   = 0.5;
    for (let gx = 0; gx < canvas.width; gx += 40) {
      ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, canvas.height); ctx.stroke();
    }
    for (let gy = 0; gy < canvas.height; gy += 40) {
      ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(canvas.width, gy); ctx.stroke();
    }

    // Draw ground line
    ctx.beginPath();
    ctx.moveTo(0, canvas.height - 20);
    ctx.lineTo(canvas.width, canvas.height - 20);
    ctx.strokeStyle = '#2a3a2a';
    ctx.lineWidth   = 1.5;
    ctx.stroke();

    // Draw tree
    const startX  = canvas.width  / 2;
    const startY  = canvas.height - 20;
    const trunkLen = Math.min(canvas.height * 0.22, 100);

    const t0 = performance.now();
    drawBranch(startX, startY, trunkLen, 0, depth, depth, spread, ratio);
    const t1 = performance.now();

    // Update stats
    statBranches.textContent = branchCount.toLocaleString();
    statDepth.textContent    = maxReachedDepth;
    statTime.textContent     = (t1 - t0).toFixed(2) + ' ms';

    // Warning
    const totalBranches = Math.pow(2, depth) - 1;
    if (depth >= 10) {
      warnBranchCount.textContent = totalBranches.toLocaleString() + ' branches';
      warningBanner.classList.add('visible');
    } else {
      warningBanner.classList.remove('visible');
    }

    // Update slider display values
    depthVal.textContent = depth;
    angleVal.textContent = angleSlider.value + '°';
    ratioVal.textContent = ratio.toFixed(2);

    // Update call-stack visualiser
    updateStackVis(depth);
  }

  /* ─────────────────────────────────────────────
     CALL-STACK VISUALISER (simulated)
  ───────────────────────────────────────────── */
  function updateStackVis(depth) {
    stackVis.innerHTML = '';
    const show = Math.min(depth, 6);
    for (let i = 1; i <= show; i++) {
      const frame = document.createElement('div');
      frame.className = 'stack-frame' + (i === show ? ' top' : '');
      frame.textContent = `drawBranch(…, depth=${i})`;
      stackVis.appendChild(frame);
    }
    if (depth > 6) {
      const ellipsis = document.createElement('div');
      ellipsis.className = 'stack-frame';
      ellipsis.textContent = `… ${depth - 6} more frames …`;
      ellipsis.style.color = '#8b949e';
      stackVis.appendChild(ellipsis);
    }
    if (depth >= 10) {
      const msg = document.createElement('div');
      msg.className = 'stack-overflow-msg';
      msg.textContent = '⚠ In a deeper real scenario this could overflow!';
      stackVis.appendChild(msg);
    }
  }

  /* ─────────────────────────────────────────────
     EVENT LISTENERS
  ───────────────────────────────────────────── */
  [depthSlider, angleSlider, ratioSlider].forEach(s => {
    s.addEventListener('input', draw);
  });

  /* ─────────────────────────────────────────────
     RESPONSIVE CANVAS RESIZE
  ───────────────────────────────────────────── */
  function resizeCanvas() {
    const maxW = Math.min(680, window.innerWidth - 64);
    canvas.width  = maxW;
    canvas.height = Math.round(maxW * (460 / 680));
    draw();
  }

  window.addEventListener('resize', resizeCanvas);

  /* ── Initial draw ── */
  resizeCanvas();
</script>
</body>
</html>
```

## What's Inside

### 🌳 The Fractal Tree
- **Recursive `drawBranch()` function** — each call draws one segment then spawns two child calls, forming a binary tree structure
- **Three sliders** control recursion depth (1–12), branch angle (10°–60°), and child/parent length ratio (0.50–0.85)
- **Live stats** show total branches drawn, max call depth reached, and render time in milliseconds
- **Visual polish** — branches graduate from warm brown (trunk) to bright green (tips), with glow dots at leaf nodes

### 📚 The Explanation Section covers three key topics:

| Topic | What's Explained |
|---|---|
| **Recursion depth** | How stack frames accumulate; a table showing branch counts vs. simultaneous frames |
| **Stack overflow** | Why engines crash (~6k–15k frame limits in V8), with a live animated call-stack diagram |
| **Solutions** | Four illustrated approaches: iterative conversion, TCO, trampolining, and memoisation — each with runnable code snippets |

