    }
    .sf-normal { background: #0c2a3f; border-color: #38bdf8; color: #7dd3fc; }
    .sf-deep   { background: #2d1a00; border-color: #fb923c; color: #fdba74; }
    .sf-crash  { background: #2d0a0a; border-color: #f87171; color: #fca5a5; }

