  </style>
</head>
<body>

  <h1>🌳 Fractal Tree &amp; Recursion Explorer</h1>

  <!-- ── Canvas Card ── -->
  <div class="canvas-card">
    <canvas id="treeCanvas" width="660" height="440"></canvas>

    <div class="controls">
      <div class="control-group">
        <label for="depthSlider">Recursion Depth: <strong id="depthVal">7</strong></label>
        <input type="range" id="depthSlider" min="1" max="12" value="7" />
      </div>
      <div class="badge-row" id="badgeRow">
        <span class="badge badge-blue">Safe</span>
      </div>
    </div>

    <!-- Depth meter -->
    <div class="depth-meter" id="depthMeter"></div>

    <div class="stats" id="statsRow">
      <div class="stat-chip">
        <span class="val" id="statBranches">0</span>
        <span class="lbl">Branches drawn</span>
      </div>
      <div class="stat-chip">
        <span class="val" id="statCalls">0</span>
        <span class="lbl">Recursive calls</span>
      </div>
      <div class="stat-chip">
        <span class="val" id="statMaxStack">0</span>
        <span class="lbl">Max stack depth</span>
      </div>
    </div>
  </div>

  <!-- ── Explanation ── -->
  <div class="explanation">

    <div class="section-title">Understanding Recursion &amp; Its Limits</div>

    <!-- Card 1 – What is recursion depth -->
    <div class="card">
      <div class="card-header">
        <div class="icon icon-blue">🔁</div>
        <span class="card-title">What is Recursion Depth?</span>
      </div>
      <p>
        Every time a function calls <strong>itself</strong>, the JavaScript engine pushes a new
        <em>stack frame</em> onto the <strong>call stack</strong> – a fixed-size region of memory
        that stores local variables, arguments, and the return address. The <em>recursion depth</em>
        is simply how many of these frames are alive at the same time.
      </p>
      <p>
        For our fractal tree, each branch spawns <strong>two child calls</strong>. At depth <em>d</em>
        the tree contains <strong>2<sup>d+1</sup> − 1</strong> total nodes, so the number of
        branches grows <em>exponentially</em>. The stack itself only ever needs to hold
        <strong>d + 1</strong> frames at once (one per level of the current path from root to leaf).
      </p>
      <!-- Depth meter label -->
      <p style="font-size:0.8rem; color:#64748b; margin-bottom:-6px;">Live depth indicator (current slider value highlighted):</p>
      <div class="depth-meter">
        <div class="depth-cell active">1</div>
        <div class="depth-cell active">2</div>
        <div class="depth-cell active">3</div>
        <div class="depth-cell active">4</div>
        <div class="depth-cell active">5</div>
        <div class="depth-cell active">6</div>
        <div class="depth-cell active">7</div>
        <div class="depth-cell">8</div>
        <div class="depth-cell">9</div>
        <div class="depth-cell danger">10</div>
        <div class="depth-cell danger">11</div>
        <div class="depth-cell danger">12</div>
      </div>
    </div>

    <!-- Card 2 – Stack overflow -->
    <div class="card">
      <div class="card-header">
        <div class="icon icon-orange">💥</div>
        <span class="card-title">Why Deep Recursion Causes Stack Overflow</span>
      </div>
      <p>
        The call stack has a hard size limit set by the JavaScript engine (typically
        <strong>~10 000 – 15 000 frames</strong> in V8/Node, fewer in some browsers). When a
        recursive function never reaches its base case – or the depth is simply too large – the
        stack runs out of space and the engine throws a
        <strong style="color:#f87171;">RangeError: Maximum call stack size exceeded</strong>.
      </p>
      <p>
        This is called a <strong>stack overflow</strong>. Unlike a heap allocation failure, you
        cannot catch it reliably and execution halts. Even well-written recursive code can hit
        this limit if the input data is large enough (e.g., traversing a million-node linked list
        recursively).
      </p>

      <!-- Stack visualisation -->
      <p style="font-size:0.8rem;color:#64748b;">Conceptual call stack at depth 5 (bottom = first call):</p>
      <div class="stack-vis">
        <div class="stack-frame sf-normal">drawBranch(depth=0, …)  ← base case, returns</div>
        <div class="stack-frame sf-normal">drawBranch(depth=1, …)</div>
        <div class="stack-frame sf-normal">drawBranch(depth=2, …)</div>
        <div class="stack-frame sf-normal">drawBranch(depth=3, …)</div>
        <div class="stack-frame sf-normal">drawBranch(depth=4, …)</div>
        <div class="stack-frame sf-normal">drawBranch(depth=5, …)  ← entry point</div>
      </div>

      <pre><span class="cm">// A naive infinite recursion – instant stack overflow</span>
<span class="kw">function</span> <span class="fn">boom</span>() {
  <span class="kw">return</span> <span class="fn">boom</span>(); <span class="cm">// no base case → RangeError!</span>
}

<span class="cm">// A deep-but-finite recursion that still overflows on large n</span>
<span class="kw">function</span> <span class="fn">sum</span>(n) {
  <span class="kw">if</span> (n === <span class="num">0</span>) <span class="kw">return</span> <span class="num">0</span>;
  <span class="kw">return</span> n + <span class="fn">sum</span>(n - <span class="num">1</span>); <span class="cm">// sum(1_000_000) → stack overflow</span>
}</pre>
    </div>

    <!-- Card 3 – Solutions -->
    <div class="card">
      <div class="card-header">
        <div class="icon icon-green">🛠️</div>
        <span class="card-title">Practical Solutions</span>
      </div>

      <!-- 3a Iterative -->
      <p><strong>1 · Iterative Approach (Explicit Stack)</strong></p>
      <p>
        Replace the call stack with a <strong>data structure you control</strong> – usually an
        array used as a stack or queue. Because heap memory is far larger than the call stack,
        you can process millions of items without overflow. This is the most universally portable
        solution and works in every JavaScript environment.
      </p>
      <pre><span class="cm">// Iterative fractal tree using an explicit stack</span>
<span class="kw">function</span> <span class="fn">drawTreeIterative</span>(ctx, x, y, angle, length, depth) {
  <span class="kw">const</span> stack = [{ x, y, angle, length, depth }];

  <span class="kw">while</span> (stack.length > <span class="num">0</span>) {
    <span class="kw">const</span> { x, y, angle, length, depth } = stack.<span class="fn">pop</span>();
    <span class="kw">if</span> (depth === <span class="num">0</span> || length < <span class="num">1</span>) <span class="kw">continue</span>;

    <span class="kw">const</span> x2 = x + length * Math.<span class="fn">cos</span>(angle);
    <span class="kw">const</span> y2 = y + length * Math.<span class="fn">sin</span>(angle);
    <span class="fn">drawLine</span>(ctx, x, y, x2, y2);

    stack.<span class="fn">push</span>({ x: x2, y: y2, angle: angle - <span class="num">0.4</span>, length: length * <span class="num">0.72</span>, depth: depth - <span class="num">1</span> });
    stack.<span class="fn">push</span>({ x: x2, y: y2, angle: angle + <span class="num">0.4</span>, length: length * <span class="num">0.72</span>, depth: depth - <span class="num">1</span> });
  }
}</pre>

      <!-- 3b TCO -->
      <p><strong>2 · Tail Call Optimisation (TCO)</strong></p>
      <p>
        A <em>tail call</em> occurs when a recursive call is the <strong>very last operation</strong>
        in a function – nothing happens after it returns. A TCO-capable engine can <em>reuse</em>
        the current stack frame instead of pushing a new one, making the recursion use
        <strong>O(1) stack space</strong>. ES2015 mandated TCO in strict mode, but as of 2024
        <strong>only JavaScriptCore (Safari) implements it</strong>; V8 (Chrome/Node) and
        SpiderMonkey (Firefox) do not.
      </p>
      <pre><span class="cm">// Tail-recursive factorial (works with TCO)</span>
<span class="str">"use strict"</span>;
<span class="kw">function</span> <span class="fn">factorial</span>(n, acc = <span class="num">1</span>) {
  <span class="kw">if</span> (n <= <span class="num">1</span>) <span class="kw">return</span> acc;
  <span class="kw">return</span> <span class="fn">factorial</span>(n - <span class="num">1</span>, n * acc); <span class="cm">// tail position – no work after call</span>
}

<span class="cm">// Binary-branching trees CANNOT be tail-call optimised because
// each call spawns TWO children – work remains after the first returns.</span></pre>

      <!-- 3c Trampolining -->
      <p><strong>3 · Trampolining</strong></p>
      <p>
        A <em>trampoline</em> is a higher-order function that repeatedly calls a thunk (a
        zero-argument function) until it receives a plain value. This simulates TCO in engines
        that don't support it natively, keeping the call stack depth at <strong>O(1)</strong>.
      </p>
      <pre><span class="kw">const</span> <span class="fn">trampoline</span> = fn => (...args) => {
  <span class="kw">let</span> result = <span class="fn">fn</span>(...args);
  <span class="kw">while</span> (<span class="kw">typeof</span> result === <span class="str">'function'</span>) result = <span class="fn">result</span>();
  <span class="kw">return</span> result;
};

<span class="kw">const</span> <span class="fn">factorial</span> = <span class="fn">trampoline</span>(<span class="kw">function</span> <span class="fn">fact</span>(n, acc = <span class="num">1</span>) {
  <span class="kw">if</span> (n <= <span class="num">1</span>) <span class="kw">return</span> acc;
  <span class="kw">return</span> () => <span class="fn">fact</span>(n - <span class="num">1</span>, n * acc); <span class="cm">// return a thunk, not a direct call</span>
});

<span class="fn">factorial</span>(<span class="num">1_000_000</span>); <span class="cm">// ✅ no stack overflow</span></pre>

      <!-- 3d Memoisation -->
      <p><strong>4 · Memoisation + Depth Guards</strong></p>
      <p>
        For problems with <em>overlapping sub-problems</em> (e.g., Fibonacci), caching results
        with a <strong>Map</strong> prevents redundant calls and exponential blow-up. Always
        pair recursion with an explicit <strong>depth guard</strong> to fail fast with a clear
        error rather than a cryptic stack overflow.
      </p>
      <pre><span class="kw">const</span> MAX_DEPTH = <span class="num">500</span>;
<span class="kw">const</span> memo = <span class="kw">new</span> Map();

<span class="kw">function</span> <span class="fn">fib</span>(n, depth = <span class="num">0</span>) {
  <span class="kw">if</span> (depth > MAX_DEPTH) <span class="kw">throw new</span> Error(<span class="str">`Depth limit reached at n=${n}`</span>);
  <span class="kw">if</span> (memo.<span class="fn">has</span>(n)) <span class="kw">return</span> memo.<span class="fn">get</span>(n);
  <span class="kw">if</span> (n <= <span class="num">1</span>) <span class="kw">return</span> n;
  <span class="kw">const</span> result = <span class="fn">fib</span>(n - <span class="num">1</span>, depth + <span class="num">1</span>) + <span class="fn">fib</span>(n - <span class="num">2</span>, depth + <span class="num">1</span>);
  memo.<span class="fn">set</span>(n, result);
  <span class="kw">return</span> result;
}</pre>
    </div>

    <!-- Card 4 – Comparison table -->
    <div class="card">
      <div class="card-header">
        <div class="icon icon-purple">📊</div>
        <span class="card-title">Approach Comparison</span>
      </div>
      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Approach</th>
              <th>Stack Usage</th>
              <th>Readability</th>
              <th>Portability</th>
              <th>Best For</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td><strong>Plain recursion</strong></td>
              <td><span class="pill pill-red">O(d) – limited</span></td>
              <td><span class="pill pill-green">Excellent</span></td>
              <td><span class="pill pill-green">Universal</span></td>
              <td>Small, bounded depth</td>
            </tr>
            <tr>
              <td><strong>Iterative + explicit stack</strong></td>
              <td><span class="pill pill-green">O(d) – heap</span></td>
              <td><span class="pill pill-yellow">Moderate</span></td>
              <td><span class="pill pill-green">Universal</span></td>
              <td>Trees, graphs, deep data</td>
            </tr>
            <tr>
              <td><strong>Tail call (TCO)</strong></td>
              <td><span class="pill pill-green">O(1)</span></td>
              <td><span class="pill pill-green">Excellent</span></td>
              <td><span class="pill pill-red">Safari only</span></td>
              <td>Linear tail-recursive fns</td>
            </tr>
            <tr>
              <td><strong>Trampolining</strong></td>
              <td><span class="pill pill-green">O(1)</span></td>
              <td><span class="pill pill-yellow">Moderate</span></td>
              <td><span class="pill pill-green">Universal</span></td>
              <td>TCO without engine support</span></td>
            </tr>
            <tr>
              <td><strong>Memoisation</strong></td>
              <td><span class="pill pill-yellow">O(d) – reduced</span></td>
              <td><span class="pill pill-green">Good</span></td>
              <td><span class="pill pill-green">Universal</span></td>
              <td>Overlapping sub-problems</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

  </div><!-- /explanation -->

  <footer>Built with vanilla HTML, CSS &amp; Canvas · No dependencies</footer>

<script>
(() => {
  'use strict';

  /* ── Elements ── */
  const canvas  = document.getElementById('treeCanvas');
  const ctx     = canvas.getContext('2d');
  const slider  = document.getElementById('depthSlider');
  const depthLbl= document.getElementById('depthVal');
  const badgeRow= document.getElementById('badgeRow');
  const statBranches = document.getElementById('statBranches');
  const statCalls    = document.getElementById('statCalls');
  const statMaxStack = document.getElementById('statMaxStack');

  /* ── Counters ── */
  let branchCount = 0;
  let callCount   = 0;
  let maxStack    = 0;

  /* ── Colour palette per depth level ── */
  const palette = [
    '#a16207','#ca8a04','#eab308',   // trunk / thick
    '#65a30d','#4ade80','#86efac',   // mid branches
    '#38bdf8','#818cf8','#c084fc',   // upper
    '#f472b6','#fb7185','#fda4af'    // tips
  ];

  /* ── Draw one branch recursively ── */
  function drawBranch(x1, y1, angle, length, depth, stackDepth) {
    callCount++;
    if (stackDepth > maxStack) maxStack = stackDepth;

    if (depth === 0 || length < 1) return;

    const x2 = x1 + length * Math.cos(angle);
    const y2 = y1 + length * Math.sin(angle);

    /* Stroke style */
    const lw = Math.max(0.5, depth * 0.9);
    ctx.lineWidth   = lw;
    ctx.strokeStyle = palette[Math.min(depth - 1, palette.length - 1)];
    ctx.shadowColor = palette[Math.min(depth - 1, palette.length - 1)];
    ctx.shadowBlur  = depth > 4 ? 4 : 0;

    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.stroke();
    branchCount++;

    const newLen   = length * 0.72;
    const spread   = 0.38 + (depth < 4 ? 0.05 : 0);

    drawBranch(x2, y2, angle - spread, newLen, depth - 1, stackDepth + 1);
    drawBranch(x2, y2, angle + spread, newLen, depth - 1, stackDepth + 1);
  }

  /* ── Redraw ── */
  function redraw() {
    const depth = parseInt(slider.value, 10);

    /* Reset counters */
    branchCount = 0;
    callCount   = 0;
    maxStack    = 0;

    /* Clear */
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    /* Trunk start */
    const cx     = canvas.width / 2;
    const base   = canvas.height - 20;
    const trunkH = Math.min(canvas.height * 0.28, 120);

    /* Draw */
    drawBranch(cx, base, -Math.PI / 2, trunkH, depth, 1);

    /* Update label */
    depthLbl.textContent = depth;

    /* Update stats */
    statBranches.textContent = branchCount.toLocaleString();
    statCalls.textContent    = callCount.toLocaleString();
    statMaxStack.textContent = maxStack;

    /* Update badge */
    updateBadge(depth);

    /* Update built-in depth meter */
    updateMeter(depth);
  }

  /* ── Badge logic ── */
  function updateBadge(depth) {
    badgeRow.innerHTML = '';
    const badges = [];

    if (depth <= 6) {
      badges.push(['badge-green', '✅ Safe']);
    } else if (depth <= 9) {
      badges.push(['badge-blue', '⚡ Moderate']);
    } else {
      badges.push(['badge-warn', '⚠️ Heavy']);
    }

    const total = Math.pow(2, depth + 1) - 1;
    badges.push(['badge-purple', `${total.toLocaleString()} nodes`]);
    badges.push(['badge-blue', `Stack: ${depth + 1} frames`]);

    badges.forEach(([cls, txt]) => {
      const s = document.createElement('span');
      s.className = `badge ${cls}`;
      s.textContent = txt;
      badgeRow.appendChild(s);
    });
  }

  /* ── Live depth meter (in canvas card) ── */
  const meterEl = document.getElementById('depthMeter');
  // Build cells
  for (let i = 1; i <= 12; i++) {
    const cell = document.createElement('div');
    cell.className = 'depth-cell';
    cell.textContent = i;
    cell.dataset.level = i;
    meterEl.appendChild(cell);
  }

  function updateMeter(depth) {
    meterEl.querySelectorAll('.depth-cell').forEach(cell => {
      const lvl = parseInt(cell.dataset.level, 10);
      cell.classList.remove('active', 'danger');
      if (lvl <= depth) {
        cell.classList.add(lvl >= 10 ? 'danger' : 'active');
      }
    });
  }

  /* ── Event listener ── */
  slider.addEventListener('input', redraw);

  /* ── Initial draw ── */
  redraw();

})();
</script>
</body>
</html>
```

