<pre>
<span class="cm">// Thunk: a zero-arg function deferring computation</span>
<span class="kw">const</span> <span class="fn">thunk</span> = (<span class="var">fn</span>, ...<span class="var">args</span>) => () => <span class="fn">fn</span>(...<span class="var">args</span>);

<span class="kw">function</span> <span class="fn">trampoline</span>(<span class="var">fn</span>) {
  <span class="kw">return</span> <span class="kw">function</span>(...<span class="var">args</span>) {
    <span class="kw">let</span> <span class="var">result</span> = <span class="fn">fn</span>(...<span class="var">args</span>);
    <span class="kw">while</span> (<span class="kw">typeof</span> <span class="var">result</span> === <span class="str">'function'</span>) {
      <span class="var">result</span> = <span class="var">result</span>();   <span class="cm">// unwrap one thunk at a time</span>
    }
    <span class="kw">return</span> <span class="var">result</span>;
  };
}

<span class="cm">// Factorial rewritten for trampolining (single recursive path = works cleanly)</span>
<span class="kw">const</span> <span class="fn">factT</span> = <span class="fn">trampoline</span>((<span class="var">n</span>, <span class="var">acc</span> = <span class="str">1</span>) =>
  <span class="var">n</span> <= <span class="str">1</span> ? <span class="var">acc</span> : <span class="fn">thunk</span>(<span class="fn">factT</span>, <span class="var">n</span> - <span class="str">1</span>, <span class="var">n</span> * <span class="var">acc</span>)
);
<span class="cm">// factT(100000) — no stack overflow, O(1) stack depth</span>
</pre>

